import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Ensure that user input is limited to 10 characters
        String truncatedName = name.substring(0, Math.min(name.length(), 10));

        // Use an array with appropriate length to store the input
        char[] buffer = new char[truncatedName.length()];
        truncatedName.getChars(0, truncatedName.length(), buffer, 0);

        // Accessing the buffer within its bounds
        if (buffer.length > 10) {
            System.out.println("Buffer overflow prevented. Truncated name: " + new String(buffer));
        } else {
            System.out.println("Hello, " + new String(buffer));
        }
    }
}

### Explanation:
취약유형: Buffer Overflow
